{
  "name": "claude-trail",
  "version": "0.1.0-dev.0",
  "description": "Real-time TUI dashboard for Claude Code: visualize file interactions, context boundaries (/clear, /compact), and subagent activity.",
  "type": "module",
  "bin": {
    "claude-trail": "bin/claude-trail.js",
    "claude-trail-hook": "bin/claude-trail-hook.js"
  },
  "files": [
    "bin",
    "dist",
    "README.md"
  ],
  "engines": {
    "node": ">=18"
  },
  "scripts": {
    "build": "tsc",
    "dev": "tsc --watch",
    "clean": "rm -rf dist",
    "prepublishOnly": "npm run clean && npm run build"
  },
  "dependencies": {
    "ink": "^5.0.1",
    "react": "^18.3.1"
  },
  "devDependencies": {
    "@types/node": "^20.14.0",
    "@types/react": "^18.3.3",
    "ink-testing-library": "^4.0.0",
    "typescript": "^5.5.4"
  },
  "keywords": [
    "claude",
    "claude-code",
    "tui",
    "ink",
    "observability",
    "hooks"
  ],
  "license": "MIT"
}

// claude-trail event schema — events.jsonl line types.
// One JSONL line = one event. Discriminator: `tool`.
// Spec: docs/DESIGN.md §5, §5.1.

export type FileToolName = 'Read' | 'Edit' | 'Write' | 'Glob' | 'Grep';

export type ControlEventName =
  | 'session_start'
  | 'session_end'
  | 'compact'
  | 'subagent_stop';

interface BaseEvent {
  ts: string;
  session: string;
}

export interface FileEvent extends BaseEvent {
  tool: FileToolName;
  path: string;
  ext: string | null;
  meta: ReadMeta | EditMeta | WriteMeta | GlobMeta | GrepMeta;
}

export interface TaskEvent extends BaseEvent {
  tool: 'Task';
  meta: TaskMeta;
}

export interface ControlEvent extends BaseEvent {
  tool: '_control';
  event: ControlEventName;
  meta: ControlMeta;
}

export type TrailEvent = FileEvent | TaskEvent | ControlEvent;

// Per-tool meta payloads (§5.1.1)

export interface ReadMeta {
  offset?: number;
  limit?: number;
  outside?: boolean;
}

export interface EditMeta {
  replace_all?: boolean;
  outside?: boolean;
}

export interface WriteMeta {
  bytes?: number;
  outside?: boolean;
}

export interface GlobMeta {
  pattern: string;
  outside?: boolean;
}

export interface GrepMeta {
  query: string;
  glob?: string;
  type?: string;
  outside?: boolean;
}

export interface TaskMeta {
  subagent_type: string;
  description: string;
  task_id: string;
}

// Control event meta — discriminated by ControlEvent.event (§5.1.2, §5.1.3)

export type ControlMeta =
  | SessionStartMeta
  | SessionEndMeta
  | CompactMeta
  | SubagentStopMeta;

export interface SessionStartMeta {
  source: 'startup' | 'resume' | 'clear';
}

export interface SessionEndMeta {
  reason: 'clear' | 'logout' | 'prompt_input_exit' | 'other';
}

export interface CompactMeta {
  trigger: 'manual' | 'auto';
}

export interface SubagentStopMeta {
  parent_task_id?: string;
}

// Hook stdin payload shapes (Claude Code → claude-trail-hook).
// Source: https://docs.claude.com/en/docs/claude-code/hooks

export type HookEventName =
  | 'PostToolUse'
  | 'SessionStart'
  | 'SessionEnd'
  | 'PreCompact'
  | 'SubagentStop';

interface BaseHookPayload {
  session_id: string;
  transcript_path: string;
  cwd: string;
  hook_event_name: HookEventName;
}

export interface PostToolUsePayload extends BaseHookPayload {
  hook_event_name: 'PostToolUse';
  tool_name: string;
  tool_input: Record<string, unknown>;
  tool_response?: unknown;
}

export interface SessionStartPayload extends BaseHookPayload {
  hook_event_name: 'SessionStart';
  source: 'startup' | 'resume' | 'clear';
}

export interface SessionEndPayload extends BaseHookPayload {
  hook_event_name: 'SessionEnd';
  reason: 'clear' | 'logout' | 'prompt_input_exit' | 'other';
}

export interface PreCompactPayload extends BaseHookPayload {
  hook_event_name: 'PreCompact';
  trigger: 'manual' | 'auto';
  custom_instructions?: string;
}

export interface SubagentStopPayload extends BaseHookPayload {
  hook_event_name: 'SubagentStop';
  stop_hook_active?: boolean;
  subagent_session_id?: string;
}

export type HookPayload =
  | PostToolUsePayload
  | SessionStartPayload
  | SessionEndPayload
  | PreCompactPayload
  | SubagentStopPayload;

// Filter spec (§8) — used by both CLI args and TUI hotkey state.

export interface FilterState {
  ext: 'all' | 'md';
  tools: ReadonlySet<FileToolName | 'Task'> | 'all';
}
